"use client";

import { useState, useEffect } from "react";
import { Plus, Search, MoreHorizontal } from "lucide-react";

// Definimos o "formato" (Interface) do que esperamos receber do Django.
// IMPORTANTE: Ajuste esses campos se os nomes no seu models.py do Django forem diferentes!
interface Alpinista {
    id: number;
    nome: string;
    email: string;
    telefone: string;
    dataNascimento: number;
    endereco: string;
    nomePai: string;
    telefonePai: string;
    nomeMae: string;
    telefoneMae: string;
    restricaoSaude: string;
    medicacao: string;
    grupo: string;
    status: string;
    foto?: string;

}

export default function AlpinistasPage() {
    // Nossos "estados" (variáveis que o React monitora para atualizar a tela)
    const [alpinistas, setAlpinistas] = useState<Alpinista[]>([]);
    const [carregando, setCarregando] = useState(true);
    const [erro, setErro] = useState("");

    // O useEffect com array vazio [] roda apenas uma vez, assim que a página abre.
    useEffect(() => {
        buscarAlpinistas();
    }, []);

    // Função que vai no Django buscar os dados
    const buscarAlpinistas = async () => {
        try {
            // 1. Pegamos o crachá (Token) que guardamos no Cookie
            const getCookie = (nome: string) => {
                const valor = `; ${document.cookie}`;
                const partes = valor.split(`; ${nome}=`);
                if (partes.length === 2) return partes.pop()?.split(';').shift();
                return null;
            };
            
            const token = getCookie('sia_token');

            if (!token) {
                throw new Error("Token de autenticação não encontrado.");
            }

            // 2. Fazemos o GET na rota do Django, enviando o Token no cabeçalho (Headers)
            const resposta = await fetch("http://localhost:8000/api/alpinistas/", {
                method: "GET",
                headers: {
                    "Content-Type": "application/json",
                    // O "Bearer" é o padrão que o SimpleJWT do Django exige
                    "Authorization": `Bearer ${token}` 
                }
            });

            if (!resposta.ok) {
                throw new Error("Não foi possível carregar a lista de alpinistas.");
            }

            // 3. Convertemos a resposta para JSON e guardamos no nosso estado
            const dados = await resposta.json();
            setAlpinistas(dados);

        } catch (error: any) {
            setErro(error.message);
        } finally {
            // Independentemente de dar certo ou errado, paramos o "carregando"
            setCarregando(false);
        }
    };

    return (
        <div className="space-y-6">
            
            {/* Cabeçalho da Página */}
            <div className="flex justify-between items-center bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
                <div>
                    <h1 className="text-2xl font-bold text-gray-800">Alpinistas</h1>
                    <p className="text-sm text-gray-500 mt-1">Gerencie os membros do Movimento Escalada.</p>
                </div>
                <button className="bg-escalada-azul hover:bg-blue-800 text-white px-5 py-2.5 rounded-lg font-medium flex items-center gap-2 transition-colors shadow-sm">
                    <Plus size={20} />
                    Novo Alpinista
                </button>
            </div>

            {/* Barra de Pesquisa e Filtros */}
            <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex gap-4">
                <div className="flex-1 relative">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                        <Search className="h-5 w-5 text-gray-400" />
                    </div>
                    <input 
                        type="text" 
                        placeholder="Buscar por nome, email ou telefone..." 
                        className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-escalada-azul/20 focus:border-escalada-azul transition-all"
                    />
                </div>
            </div>

            {/* Área da Tabela */}
            <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
                {/* Tratamento de Estados (Carregando e Erro) */}
                {carregando && (
                    <div className="p-10 text-center text-gray-500 font-medium">
                        Carregando dados do banco...
                    </div>
                )}

                {erro && (
                    <div className="p-10 text-center text-red-500 font-medium bg-red-50">
                        {erro}
                    </div>
                )}

                {/* A Tabela de Dados */}
                {!carregando && !erro && alpinistas.length === 0 && (
                    <div className="p-10 text-center text-gray-500">
                        Nenhum alpinista cadastrado ainda. Clique em "Novo Alpinista" para começar.
                    </div>
                )}

                {!carregando && !erro && alpinistas.length > 0 && (
                    <div className="overflow-x-auto">
                        <table className="w-full text-left border-collapse">
                            <thead>
                                <tr className="bg-gray-50 border-b border-gray-100 text-sm text-gray-500 uppercase tracking-wider">
                                    <th className="px-6 py-4 font-medium">Nome</th>
                                    <th className="px-6 py-4 font-medium">E-mail</th>
                                    <th className="px-6 py-4 font-medium">Telefone</th>
                                    <th className="px-6 py-4 font-medium text-right">Ações</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-100">
                                {alpinistas.map((alpinista) => (
                                    <tr key={alpinista.id} className="hover:bg-gray-50 transition-colors">
                                        
                                        {/* A COLUNA NOME AGORA TEM A FOTO */}
                                        <td className="px-6 py-6 flex items-center gap-4">
                                            {/* Lógica do Avatar: Se tem foto, mostra a imagem. Se não, mostra a inicial. */}
                                            {alpinista.foto ? (
                                                <img 
                                                    src={alpinista.foto} 
                                                    alt={`Foto de ${alpinista.nome}`} 
                                                    className="w-12 h-12 rounded-full object-cover border border-gray-200"
                                                />
                                            ) : (
                                                <div className="w-12 h-12 rounded-full bg-blue-50 text-escalada-azul flex items-center justify-center font-bold text-sm border border-blue-100">
                                                    {/* Pega a primeira letra do nome e deixa maiúscula */}
                                                    {alpinista.nome.charAt(0).toUpperCase()}
                                                </div>
                                            )}
                                            
                                            {/* O Nome ao lado da foto */}
                                            <span className="text-base font-medium text-gray-900">
                                                {alpinista.nome}
                                            </span>
                                        </td>

                                        <td className="px-6 py-6 text-sm text-gray-500">
                                            {alpinista.email || "Não informado"}
                                        </td>
                                        <td className="px-6 py-6 text-sm text-gray-500">
                                            {alpinista.telefone || "Não informado"}
                                        </td>
                                        <td className="px-6 py-6 text-sm text-right">
                                            <button className="text-gray-400 hover:text-escalada-azul transition-colors p-2 rounded-lg hover:bg-blue-50">
                                                <MoreHorizontal size={24} />
                                            </button>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                )}
            </div>

        </div>
    );
}